import React, { useState, forwardRef, Ref } from "react";
import { Button } from "@mui/material";
import { useNavigate } from "react-router-dom";
import "./Sidebar.css";

interface SidebarProps {
    activeLink: string;
    onLinkClick: (link: string) => void;
    isSidebarOpen: boolean;
}

const Sidebar: React.FC<SidebarProps & { ref?: Ref<HTMLDivElement> }> = forwardRef<HTMLDivElement, SidebarProps>(({ activeLink, onLinkClick, isSidebarOpen }, ref) => {
    const [isLoggingOut, setIsLoggingOut] = useState(false);
    const navigate = useNavigate();

    const handleLogout = () => {
        setIsLoggingOut(true);
        setTimeout(() => {
            navigate("/login");
        }, 1000);
    };

    return (
        <div ref={ref} className={`sidebar ${isSidebarOpen ? "open" : ""}`}>
            <ul className="sidebar-menu">
                {["Real-Time Pricing", "Inventory", "Alerts", "Analytics", "Settings", "Help"].map((item) => (
                    <li
                        key={item}
                        className={activeLink === item ? "active" : ""}
                        onClick={() => onLinkClick(item)}
                    >
                        {item}
                    </li>
                ))}
            </ul>
            <Button
                className="logout-button"
                onClick={handleLogout}
                variant="contained"
                color="error"
            >
                {isLoggingOut ? "Logging out..." : "Logout"}
            </Button>
        </div>
    );
});

export default Sidebar;
